'use client';
import { useToast } from '@/hooks/use-toast';
import { getStatusStyle } from './buttonStatus';
import {
  Dialog,
  DialogTrigger,
  DialogContent,
  DialogTitle,
  DialogDescription,
  DialogClose,
} from '@/components/ui/dialog';
import React, { useState, useEffect } from 'react';
import {
  History,
  CheckCircle,
  XCircle,
  Clock as PendingIcon,
  MapPin,
  University,
  Flame,
  Rocket,
  Type,
  Calendar1,
  Building,
  List,
  Calendar,
  ShieldCheck,
  X,
  Download,
  Plus,
  Eye,
  Edit,
  Trash2,
} from 'lucide-react';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { motion, AnimatePresence } from 'framer-motion';
import EventCard from '@/components/ui/EventCard';
import { EventCategory } from '@/types';
import { useDebounce } from 'use-debounce';
import Link from 'next/link';
import { Calendar as CalendarComp } from '@/components/ui/calendar';
import { Button } from '@/components/ui/button';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { useAuth } from '@/context/AuthContext';
import Decorations from '@/components/ui/Decorations';
import DeleteConfirmationDialog from '@/components/dialog/DeleteConfirmationDialog';
import { StatCard } from '@/components/ui/StatCard';
import { stats } from '@/constants/stats';
import Pagination from '@/components/ui/Pagination';
import SearchInput from '@/components/ui/SearchInput';

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 0.5,
      ease: 'easeOut',
    },
  },
  hover: {
    scale: 1.02,
    transition: {
      duration: 0.3,
    },
  },
};
// تسميات الفلاتر
const filterLabels = [
  { label: 'All', icon: List, value: 'all' },
  { label: 'Upcoming', icon: Flame, value: 'upcoming' },
  { label: 'Past', icon: History, value: 'past' },
  { label: 'Pending', icon: PendingIcon, value: 'pending' },
  { label: 'Approved', icon: CheckCircle, value: 'approved' },
  { label: 'Rejected', icon: XCircle, value: 'rejected' },
];

const AllEventsPage = ({ className }: React.HTMLAttributes<HTMLDivElement>) => {
  const { toast } = useToast();
  const { token } = useAuth();
  const [events, setEvents] = useState<EventCategory[]>([]);
  const [date, setDate] = useState<Date | undefined>(new Date());
  const [activeFilter, setActiveFilter] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);
  const [isCalendarOpen, setIsCalendarOpen] = useState(false);

  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);

  const [currentPage, setCurrentPage] = useState(1); // حالة Pagination الجديدة
  const [totalPages, setTotalPages] = useState(0);
  const [totalItems, setTotalItems] = useState(0);
  const [eventsPerPage] = useState(6); // عدد الأحداث في كل صفحة

  const [loading, setLoading] = useState(false);
  const [statusButton, setStatusButton] = useState('');
  const [selectedEvent, setSelectedEvent] = useState<EventCategory | null>(
    null
  );
  const [downloadingReportpdf, setDownloadingReportpdf] = useState<
    string | null
  >(null);

  // Function to download invoice
  const downloadingReport = async (eventId: string) => {
    if (!token) return;

    setDownloadingReportpdf(eventId);
    try {
      const response = await fetch(
        `http://localhost:8080/reports/event/${eventId}`,
        {
          method: 'GET',
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      if (!response.ok) {
        throw new Error(await response.text());
      }

      // Create blob from response
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);

      // Create download link
      const a = document.createElement('a');
      a.href = url;
      a.download = `Invoice-${eventId}.pdf`;
      document.body.appendChild(a);
      a.click();

      // Cleanup
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      toast({
        title: 'Invoice downloaded',
        description: 'The invoice has been successfully downloaded.',
        className: 'bg-green-500 text-white',
      });
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'Failed to download invoice',
        className: 'bg-red-600 text-white border-0',
      });
    } finally {
      setDownloadingReportpdf(null);
    }
  };

  const fetchEvents = async () => {
    setLoading(true);

    const filterType =
      activeFilter === 'all'
        ? ''
        : activeFilter === 'upcoming'
        ? 'upcoming'
        : activeFilter === 'past'
        ? 'past'
        : '';
    try {
      const res = await fetch(
        `http://localhost:8080/admin/events?page=${currentPage}&perPage=${eventsPerPage}&type=${filterType}`,
        {
          method: 'GET',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );
      const data = await res.json();
      setEvents(data.events);
      setTotalPages(data.totalPages);
      setTotalItems(data.totalItems);
    } catch (error: any) {
      // Handle connection errors or unexpected errors.
      toast({
        title: 'Error',
        description: error?.message || 'An unexpected error occurred.',
        className: 'bg-red-600 text-white border-0',
      });
    } finally {
      setLoading(false);
    }
  };
  useEffect(() => {
    if (token) {
      fetchEvents();
    }
  }, [activeFilter, currentPage, token]);

  const approvedCount = events.filter((e) => e.status === 'approved').length;
  const pendingCount = events.filter((e) => e.status === 'pending').length;
  const rejectedCount = events.filter((e) => e.status === 'rejected').length;

  // تصفية الأحداث
  const currentEvents = events?.filter((event) => {
    const matchesSearch = event?.title
      ?.toLowerCase()
      .includes(debouncedQuery.toLowerCase());
    const matchesFilter =
      activeFilter === 'all' ||
      (activeFilter === 'upcoming' && event.status === 'upcoming') ||
      (activeFilter === 'past' && event.status === 'past') ||
      (activeFilter === 'pending' && event.status === 'pending') ||
      (activeFilter === 'approved' && event.status === 'approved') ||
      (activeFilter === 'rejected' && event.status === 'rejected');

    return matchesSearch && matchesFilter;
  });

  // تغيير الصفحة
  const paginate = (pageNumber: number) => setCurrentPage(pageNumber);

  const handleStatusChange = async ({
    url,
    method = 'PATCH',
    successMessage = 'Updated successfully',
    onSuccess,
  }: {
    url: string;
    method?: 'PATCH' | 'POST' | 'DELETE';
    successMessage?: string;
    onSuccess?: () => void;
  }) => {
    try {
      setLoading(true);

      const response = await fetch(url, {
        method,
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
      });

      const data = await response.json();
      toast({
        title: successMessage,
        description: data.message,
        className: 'bg-green-500 text-white',
      });

      if (onSuccess) onSuccess();
    } catch (err: any) {
      toast({
        variant: 'destructive',
        title: 'Error',
        description: err.message,
      });
    } finally {
      setLoading(false);
    }
  };
  const onApprove = () => {
    if (!selectedEvent) return;

    handleStatusChange({
      url: `http://localhost:8080/admin/events/${selectedEvent._id}/approve`,
      method: 'PATCH',
      successMessage: 'The event has been approved.',
      onSuccess: () => {
        setEvents((prev) =>
          prev.map((e) =>
            e._id === selectedEvent._id ? { ...e, status: 'approved' } : e
          )
        );
        setSelectedEvent(null);
      },
    });
  };
  const onReject = () => {
    if (!selectedEvent) return;

    handleStatusChange({
      url: `http://localhost:8080/admin/events/${selectedEvent._id}/reject`,
      method: 'PATCH',
      successMessage: 'The event has been rejected.',
      onSuccess: () => {
        setEvents((prev) =>
          prev.map((e) =>
            e._id === selectedEvent._id ? { ...e, status: 'rejected' } : e
          )
        );
        setSelectedEvent(null);
      },
    });
  };
  // Handle delete
  const handleDelete = (event: EventCategory) => {
    setSelectedEvent(event);
    setIsDeleteModalOpen(true);
  };
  const confirmDelete = async () => {
    if (!selectedEvent) return;

    try {
      const res = await fetch(
        `http://localhost:8080/host/events/${selectedEvent._id}`,
        {
          method: 'DELETE',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );
      const data = await res.json();
      toast({
        title: 'Event Deleted',
        description: data.message,
        className: 'bg-green-600 text-white border-0',
      });
      setEvents((prev) =>
        prev.filter((event) => event._id !== selectedEvent._id)
      );
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'An unexpected error occurred.',
        className: 'bg-red-500 text-white border-0',
      });
    }

    setIsDeleteModalOpen(false);
    setSelectedEvent(null);
  };
  const statsValue = {
    totalItems: totalItems,
  };

  // إعادة تعيين الصفحة إلى 1 عند تغيير الفلتر
  useEffect(() => {
    setCurrentPage(1);
  }, [activeFilter]);

  return (
    <main className='bg-white min-h-screen relative'>
      <div className='max-w-6xl mx-auto px-4 relative'>
        {/* Stats */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.4 }}
          className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6'
        >
          {stats.map((stat, index) => (
            <StatCard
              key={index}
              title={stat.title}
              value={statsValue.totalItems}
              change={stat.change}
              icon={stat.icon}
              delay={index * 0.1}
            />
          ))}
        </motion.div>
        {/* Controls */}
        <motion.div
          className='flex flex-col lg:flex-row gap-4 items-stretch my-8'
          variants={itemVariants}
        >
          {/* Search Input */}
          <SearchInput
            name='Events'
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            setCurrentPage={() => setCurrentPage(1)}
          />
          {/* Filters Tabs */}
          <div className='flex-1 overflow-x-auto'>
            <Tabs
              value={activeFilter}
              onValueChange={(val) => {
                setActiveFilter(val);
                setCurrentPage(1);
              }}
              className='w-full'
            >
              <TabsList className='bg-transparent gap-1 p-1 flex-wrap justify-start w-full'>
                {filterLabels.map(({ label, icon: Icon, value }) => (
                  <TabsTrigger
                    value={value}
                    key={value}
                    className='data-[state=active]:bg-purple-600 data-[state=active]:text-white rounded-full px-3 py-1 text-xs md:text-sm md:px-4 md:py-2 transition-all whitespace-nowrap'
                  >
                    <div className='flex items-center gap-1 md:gap-2'>
                      <Icon className='h-3 w-3 md:h-4 md:w-4' />
                      {label}
                    </div>
                  </TabsTrigger>
                ))}
              </TabsList>
            </Tabs>
          </div>

          {/* Calendar Popover */}
          <Popover
            open={isCalendarOpen}
            onOpenChange={setIsCalendarOpen}
          >
            <PopoverTrigger asChild>
              <Button
                variant='outline'
                className='rounded-full gap-2'
              >
                <Calendar className='h-4 w-4' />
                <span>Select Date</span>
              </Button>
            </PopoverTrigger>
            <PopoverContent
              className='w-auto p-0'
              align='end'
            >
              <CalendarComp
                mode='single'
                selected={date}
                onSelect={(selectedDate) => {
                  setDate(selectedDate);
                  setIsCalendarOpen(false);
                }}
                initialFocus
              />
            </PopoverContent>
          </Popover>
          {/* Create Event */}
          <Button className='bg-gradient-to-r from-purple-800 to-pink-700'>
            <Plus className='text-white'></Plus>
            <Link href='/create'>Create Events</Link>
          </Button>
        </motion.div>
        <motion.div
          className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8'
          initial='hidden'
          animate='visible'
          variants={{
            hidden: { opacity: 0 },
            visible: {
              opacity: 1,
              transition: {
                staggerChildren: 0.1,
                delayChildren: 0.2,
              },
            },
          }}
        >
          <AnimatePresence>
            {currentEvents?.length > 0 ? (
              currentEvents.map((event) => {
                const statusInfo = getStatusStyle(event.status);
                return (
                  <motion.div
                    key={event._id}
                    variants={{
                      hidden: { opacity: 0, y: 20 },
                      visible: { opacity: 1, y: 0 },
                    }}
                    whileHover={{
                      y: -5,
                      transition: { type: 'spring', stiffness: 300 },
                    }}
                    className='relative group'
                  >
                    <EventCard
                      event={event}
                      className='transition-all duration-300 group-hover:shadow-xl group-hover:shadow-purple-500/20 group-hover:border-cyan-400/30'
                    >
                      {/* محتوى البطاقة */}
                      <div className='p-4 md:p-6 bg-white shadow-xl rounded-2xl space-y-4 md:space-y-6 hover:shadow-purple-200 transition-all duration-300 relative'>
                        {/* Paid/Free Badge */}
                        {event.price ? (
                          <motion.div
                            initial={{ scale: 0, rotate: -15 }}
                            animate={{ scale: 1, rotate: -15 }}
                            className='absolute top-2 left-2 px-3 py-1 bg-red-500/90 rounded-md backdrop-blur-sm transform skew-x-12 shadow-lg z-10'
                          >
                            <span className='text-white font-bold italic text-sm'>
                              PAID
                            </span>
                          </motion.div>
                        ) : (
                          <motion.div
                            initial={{ scale: 0, rotate: -15 }}
                            animate={{ scale: 1, rotate: -15 }}
                            className='absolute top-2 left-2 px-3 py-1 bg-green-500/90 rounded-md backdrop-blur-sm transform skew-x-12 shadow-lg z-10'
                          >
                            <span className='text-white font-bold italic text-sm'>
                              FREE
                            </span>
                          </motion.div>
                        )}

                        <Link href={`events/${event._id}`}>
                          {/* Header - Category and Status */}
                          <div className='flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 mb-4'>
                            {/* التصنيف */}
                            <div className='flex items-center gap-2 bg-clip-text text-transparent bg-gradient-to-r from-pink-600 via-purple-400 to-indigo-400'>
                              <span className='text-xl sm:text-2xl md:text-3xl font-medium'>
                                {event.category?.name}
                              </span>
                            </div>
                            <div
                              className={`flex items-center gap-2 px-3 py-1 text-xs sm:text-sm font-medium rounded-full ${statusInfo.className}`}
                            >
                              {statusInfo.icon}
                              <span>{statusInfo.label}</span>
                            </div>
                          </div>

                          {/* العنوان والقسم والوقت */}
                          <div className='flex flex-col sm:flex-row justify-between items-start gap-4 mb-4 md:mb-6'>
                            <div className='space-y-2 flex-1'>
                              <div className='flex items-center gap-2 text-gray-800'>
                                <Type className='w-4 h-4 text-purple-600 flex-shrink-0' />
                                <h3 className='text-base sm:text-lg font-bold text-purple-700 line-clamp-2'>
                                  {event.title}
                                </h3>
                              </div>
                            </div>
                            <div className='flex flex-col items-start sm:items-end self-stretch justify-between'>
                              <span className='text-xs sm:text-sm text-gray-500'>
                                Time
                              </span>
                              <span className='text-lg sm:text-xl font-bold text-purple-600'>
                                {event.time}
                              </span>
                            </div>
                          </div>

                          {/* المعلومات التفصيلية */}
                          <div className='grid grid-cols-1 xs:grid-cols-2 gap-3 text-sm text-gray-700'>
                            <div className='flex items-center gap-2'>
                              <Calendar1 className='w-4 h-4 text-purple-500 flex-shrink-0' />
                              <span className='truncate'>
                                {new Date(event.createdAt).toLocaleDateString()}
                              </span>
                            </div>

                            {event.hall && (
                              <div className='flex items-center gap-2'>
                                <Building className='w-4 h-4 text-purple-500 flex-shrink-0' />
                                <span className='truncate'>
                                  Hall : {event.hall?.name}
                                </span>
                              </div>
                            )}

                            {(event.status === 'approved' ||
                              event.status === 'pending') && (
                              <div className='flex items-center gap-2'>
                                <University className='w-4 h-4 text-purple-500 flex-shrink-0' />
                                <span>Capacity : {event.capacity}</span>
                              </div>
                            )}

                            <div className='flex items-center gap-2'>
                              <MapPin className='w-4 h-4 text-purple-500 flex-shrink-0' />
                              <span className='truncate'>{event.location}</span>
                            </div>
                          </div>
                        </Link>
                        <div className='mt-4 md:mt-6 space-y-4'>
                          {/* Approve/Reject Buttons and Download */}
                          <div className='flex flex-col sm:flex-row justify-between items-stretch sm:items-center gap-3'>
                            {/* Approve/Reject Buttons */}
                            {/* Approve/Reject Buttons */}
                            <Dialog
                              onOpenChange={(isOpen) =>
                                !isOpen && setSelectedEvent(null)
                              }
                            >
                              <DialogTrigger asChild>
                                <div className='flex justify-center sm:justify-start gap-2'>
                                  {event.status === 'pending' ? (
                                    <>
                                      <Button
                                        size='sm'
                                        variant='ghost'
                                        onClick={() => {
                                          setSelectedEvent(event);
                                          setStatusButton('reject');
                                        }}
                                        className='flex items-center gap-2 border border-gray-300 flex-1 sm:flex-none'
                                      >
                                        <X className='h-4 w-4 text-red-600' />
                                        <span className='hidden xs:inline'>
                                          Reject
                                        </span>
                                      </Button>
                                      <Button
                                        size='sm'
                                        variant='ghost'
                                        onClick={() => {
                                          setSelectedEvent(event);
                                          setStatusButton('approve');
                                        }}
                                        className='flex items-center gap-2 border border-gray-300 flex-1 sm:flex-none'
                                      >
                                        <ShieldCheck className='h-4 w-4 text-green-700' />
                                        <span className='hidden xs:inline'>
                                          Approve
                                        </span>
                                      </Button>
                                    </>
                                  ) : event.status === 'approved' ? (
                                    <Button
                                      size='sm'
                                      variant='ghost'
                                      onClick={() => {
                                        setSelectedEvent(event);
                                        setStatusButton('reject');
                                      }}
                                      className='flex items-center gap-2 border border-gray-300'
                                    >
                                      <X className='h-4 w-4 text-red-600' />
                                      <span>Reject</span>
                                    </Button>
                                  ) : (
                                    <Button
                                      size='sm'
                                      variant='ghost'
                                      onClick={() => {
                                        setSelectedEvent(event);
                                        setStatusButton('approve');
                                      }}
                                      className='flex items-center gap-2 border border-gray-300'
                                    >
                                      <ShieldCheck className='h-4 w-4 text-green-700' />
                                      <span>Approve</span>
                                    </Button>
                                  )}
                                </div>
                              </DialogTrigger>

                              <DialogContent className='max-w-md mx-4'>
                                <DialogTitle className='text-purple-700 text-lg'>
                                  {statusButton === 'approve'
                                    ? 'Confirm Approve'
                                    : 'Confirm Reject'}
                                </DialogTitle>

                                <DialogDescription className='text-gray-600 mt-1'>
                                  {statusButton === 'approve' ? (
                                    <>
                                      Are you sure you want to{' '}
                                      <strong>Approve</strong> the event:
                                      <span className='font-semibold text-black'>
                                        {' '}
                                        {selectedEvent?.title}
                                      </span>
                                      ?
                                      <br />
                                      <span className='text-sm text-green-600'>
                                        This action cannot be undone ⚠️
                                      </span>
                                    </>
                                  ) : (
                                    <>
                                      Are you sure you want to{' '}
                                      <strong>Reject</strong> the event:
                                      <span className='font-semibold text-black'>
                                        {' '}
                                        {selectedEvent?.title}
                                      </span>
                                      ?
                                      <br />
                                      <span className='text-sm text-red-500'>
                                        This action cannot be undone ⚠️
                                      </span>
                                    </>
                                  )}
                                </DialogDescription>

                                <div className='flex flex-col sm:flex-row justify-end gap-2 mt-4'>
                                  <DialogClose asChild>
                                    <Button
                                      variant='outline'
                                      className='flex-1 sm:flex-none'
                                    >
                                      Cancel
                                    </Button>
                                  </DialogClose>

                                  {statusButton === 'approve' ? (
                                    <Button
                                      variant='default'
                                      onClick={() => onApprove()}
                                      disabled={loading}
                                      className='flex-1 sm:flex-none'
                                    >
                                      {loading ? 'Approving...' : 'Approve'}
                                    </Button>
                                  ) : (
                                    <Button
                                      variant='destructive'
                                      onClick={() => onReject()}
                                      disabled={loading}
                                      className='flex-1 sm:flex-none'
                                    >
                                      {loading ? 'Rejecting...' : 'Reject'}
                                    </Button>
                                  )}
                                </div>
                              </DialogContent>
                            </Dialog>

                            {/* Download Report and Price */}
                            <div className='flex items-center justify-between sm:justify-end gap-2'>
                              {/* Download Report Button */}
                              {event.status === 'approved' && (
                                <Button
                                  variant='outline'
                                  size='sm'
                                  onClick={() => downloadingReport(event._id)}
                                  disabled={downloadingReportpdf === event._id}
                                  className='flex items-center gap-2 flex-1 sm:flex-none'
                                >
                                  {downloadingReportpdf === event._id ? (
                                    'Downloading...'
                                  ) : (
                                    <>
                                      <Download className='h-4 w-4' />
                                      <span className='hidden xs:inline'>
                                        Report
                                      </span>
                                    </>
                                  )}
                                </Button>
                              )}

                              {/* Price Tag */}
                              {event.price !== 0 && (
                                <div className='flex flex-wrap gap-2'>
                                  <span className='bg-purple-50 text-purple-800 font-medium px-3 py-1 rounded-full text-sm shadow-sm'>
                                    {event.price} UE
                                  </span>
                                </div>
                              )}
                            </div>
                          </div>

                          {/* Action Buttons - View, Edit, Delete */}
                          <div className='flex gap-2 justify-between'>
                            {/* View Button */}
                            <Button
                              asChild
                              className='flex items-center gap-2 px-3 py-2 rounded-lg bg-purple-600 text-white hover:bg-purple-700 transition-all duration-200 flex-1'
                            >
                              <Link href={`/admin/events/${event._id}`}>
                                <Eye className='h-4 w-4' />
                                <span className='hidden xs:inline'>View</span>
                              </Link>
                            </Button>

                            {/* Edit Button */}
                            <Button
                              asChild
                              className='flex items-center gap-2 px-3 py-2 rounded-lg bg-gray-100 text-gray-700 border border-gray-300 hover:bg-gray-200 transition-all duration-200 flex-1'
                            >
                              <Link href={`/admin/events/${event._id}/edit`}>
                                <Edit className='h-4 w-4' />
                                <span className='hidden xs:inline'>Edit</span>
                              </Link>
                            </Button>

                            {/* Delete Button */}
                            <Button
                              onClick={() => handleDelete(event)}
                              variant='ghost'
                              className='flex items-center justify-center p-2 rounded-full border border-gray-300 text-red-600 hover:bg-red-50 transition-all duration-200 flex-none'
                            >
                              <Trash2 className='h-4 w-4' />
                            </Button>
                          </div>
                        </div>
                      </div>
                    </EventCard>

                    {/* Actions Section */}
                    <motion.div
                      initial={{ scale: 0 }}
                      animate={{ scale: 1 }}
                      className='absolute top-2 right-2 p-2 bg-purple-600/80 rounded-full
                                    backdrop-blur-sm'
                    >
                      <Rocket
                        size={18}
                        className='text-cyan-400'
                      />
                    </motion.div>
                  </motion.div>
                );
              })
            ) : (
              <motion.div
                className='text-center py-12 space-y-4'
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
              >
                <div className='text-xl font-bold'>No events found</div>
                <p className='text-muted-foreground'>
                  {searchQuery
                    ? 'Try a different search term'
                    : 'Create your first event to get started'}
                </p>
                <Button asChild>
                  <Link href='/admin/events/create'>Create New Event</Link>
                </Button>
              </motion.div>
            )}
          </AnimatePresence>
        </motion.div>

        {/* Pagination Controls */}
        {totalItems >= eventsPerPage && (
          <Pagination
            currentPage={currentPage}
            totalPages={totalPages}
            totalItems={totalItems}
            paginate={paginate}
          />
        )}
      </div>

      {/* Decorations */}
      <Decorations />
      {/* Delete Confirmation Modal */}
      <DeleteConfirmationDialog
        open={isDeleteModalOpen}
        onOpenChange={setIsDeleteModalOpen}
        onConfirm={confirmDelete}
        user={selectedEvent}
      />
    </main>
  );
};
export default AllEventsPage;
